+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -9226,6 +9226,12 @@ void LoopVectorizationPlanner::buildVPlansWithVPRecipes(ElementCount MinVF,
   assert(OrigLoop->isInnermost() && "Inner loop expected.");

   auto MaxVFTimes2 = MaxVF * 2;
+  // Ensure MaxVFTimes2 is a power of two as required by VFRange.
+  if (!isPowerOf2_32(MaxVFTimes2.getKnownMinValue())) {
+    unsigned NewMin = bit_floor(MaxVFTimes2.getKnownMinValue());
